insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('miel-nigelle','miels','Miel de Nigelle','L''alliance ancestrale du miel doré et de la graine noire.',ARRAY['Du miel, et la graine noire — rien d''autre. C''est l''association la plus simple et la plus pure qui soit : une préparation à base de miel et de nigelle, à savourer une cuillère le matin, nature ou dans une boisson tiède.','Notre ligne est claire : un miel n''est pas un médicament. Nous ne promettons rien sur votre santé — nous vous offrons un goût franc et une histoire que peu d''aliments du quotidien peuvent revendiquer.']::text[],ARRAY['L''association fondatrice : miel et graine de nigelle, sans autre ajout','Graines entières et moulues, pour le goût et le caractère','Préparation artisanale, par petits lots','Prêt à l''emploi : une cuillère, nature ou dans une boisson tiède']::text[],'Ce qui le distingue','Préparation à base de miel et de graines de nigelle (Nigella sativa) — miel, poudre de nigelle, graines de nigelle','Préparation artisanale — Miel de France','1 à 2 cuillères à café par jour, nature ou diluées dans une boisson tiède (thé, tisane, lait) — évitez l''eau bouillante, qui dénature le miel. Délicieux aussi sur une tartine ou dans un yaourt. Remuez avant usage : les graines se déposent. À conserver à l''abri de la chaleur et de la lumière ; la cristallisation est un phénomène naturel, sans altération.',ARRAY['Ne pas donner aux enfants de moins de 12 mois (comme tout miel)','Déconseillé aux femmes enceintes et allaitantes','En cas de traitement médical (notamment anticoagulants) ou de diabète, demandez l''avis d''un professionnel de santé','Produit artisanal : la couleur, la texture et l''intensité peuvent varier selon les lots','À conserver à l''abri de la chaleur et de la lumière']::text[],'50 g, 200 g, 300 g',NULL,9.99,ARRAY['format']::text[],ARRAY['assets/produits-ia/miel-nigelle/miel-nigelle-2.webp','assets/produits-ia/miel-nigelle/miel-nigelle-1.webp']::text[],'[{"title":"Qu''est-ce que la nigelle ?","html":"<p>De petites graines noires issues d''une fleur, <em>Nigella sativa</em>, au goût chaud et légèrement poivré qui rappelle un peu l''oignon. On l''appelle aussi <strong>graine noire</strong> ou <em>habba sawda</em>.</p><p>Méfiez-vous d''un surnom répandu : « cumin noir ». La nigelle n''a rien à voir avec le cumin — c''est une plante d''une tout autre famille. Le savoir vous évite une confusion fréquente, en cuisine comme à l''achat.</p>"},{"title":"Une graine que l''humanité n''a jamais oubliée","html":"<p>La nigelle compte parmi les épices les plus anciennes du Proche-Orient : on en suit la trace depuis plus de trois mille ans. Les médecines grecque, romaine puis arabe l''ont toutes consignée — jusqu''à Avicenne, au XI<sup>e</sup> siècle, dans l''un des traités de médecine les plus influents de l''histoire.</p><p>Cette continuité n''est pas un argument de santé : c''est un signe de confiance. Une graine qu''on se transmet sans interruption depuis l''Antiquité a forcément tenu une place réelle dans la vie des gens. C''est ce fil que vous prolongez.</p>"},{"title":"Dans la tradition islamique","html":"<p>Pour beaucoup d''entre vous, la graine noire a une valeur particulière. Nous la partageons comme un repère culturel et spirituel — jamais comme une promesse de guérison.</p><div class=\"acc-hadith\"><div class=\"ar\" dir=\"rtl\" lang=\"ar\">إِنَّ فِي الْحَبَّةِ السَّوْدَاءِ شِفَاءً مِنْ كُلِّ دَاءٍ إِلَّا السَّامَ</div><div class=\"tr\">« Il y a dans la graine noire un remède contre tout mal, sauf la mort. »</div><div class=\"ref\">Rapporté par Abū Hurayra — Ṣaḥīḥ al-Bukhārī 5688 · Ṣaḥīḥ Muslim 2215. Hadith ṣaḥīḥ (authentique), muttafaq ʿalayh.</div></div><p>Les savants eux-mêmes rappellent que « tout mal » ne se lit pas au sens littéral. La tradition invite à la mesure — et c''est dans cet esprit que nous vous transmettons cet héritage, sans en faire une garantie.</p>"},{"title":"Ce que la science sait — et ne sait pas","html":"<p>La nigelle est l''une des graines les plus étudiées au monde, en particulier pour une molécule : la <strong>thymoquinone</strong>. Cela, c''est vrai.</p><p>Mais l''essentiel de ces recherches porte sur des cellules ou des animaux. Chez l''être humain, les preuves solides manquent encore — à ce jour, rien n''est démontré. « Beaucoup étudiée » ne veut pas dire « prouvée », et nous préférons vous le dire.</p><p>Une précision honnête : un miel de nigelle reste avant tout du miel, la part de graine y est faible. Nous ne lui prêtons donc aucun pouvoir particulier — ce qui compte ici, c''est l''alliance et le goût.</p>"},{"title":"Pourquoi nous l''avons choisi","html":"<p>La nigelle existe sous bien des formes — graines à croquer, poudre, huile pour la peau, gélules dosées. Ce miel en est la version la plus douce et la plus simple : la façon la plus agréable de l''intégrer à son quotidien, sans dosage ni amertume.</p><p>Nous l''avons sélectionné pour cela, pour sa préparation artisanale par petits lots, et parce qu''il est élaboré à partir d''un <strong>miel récolté en France</strong>. Sa couleur et son intensité peuvent varier d''un pot à l''autre — la marque d''un produit vivant.</p>"},{"title":"Questions fréquentes","html":"<div class=\"faq-q\">Est-ce vraiment du miel ?</div><div class=\"faq-a\">C''est une préparation à base de miel, à laquelle on ajoute de la nigelle (en graines et moulue). Le miel en reste l''ingrédient principal.</div><div class=\"faq-q\">Quel goût a-t-il ?</div><div class=\"faq-a\">La douceur ronde du miel, relevée d''une note poivrée venue de la nigelle. Les graines entières ajoutent une légère mâche.</div><div class=\"faq-q\">Mon miel a cristallisé, est-il périmé ?</div><div class=\"faq-a\">Non. La cristallisation est naturelle, sans altération. Ne le mettez pas au réfrigérateur ; pour le rendre plus fluide, réchauffez le pot doucement au bain-marie tiède.</div><div class=\"faq-q\">Les enfants peuvent-ils en manger ?</div><div class=\"faq-a\">Oui après 1 an. Jamais avant 12 mois : comme tout miel, il est déconseillé aux nourrissons.</div><div class=\"faq-q\">Combien de temps se conserve-t-il ?</div><div class=\"faq-a\">Le miel se garde très longtemps. Conservez le pot fermé, à l''abri de la chaleur et de la lumière.</div><div class=\"faq-q\">Nigelle en miel, en huile ou en gélules ?</div><div class=\"faq-a\">L''huile s''utilise pour la peau et les cheveux ; les gélules et la poudre offrent un format dosé ; ce miel est la forme gourmande, à savourer.</div>"}]'::jsonb,true,false,0) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('miel-aphrodisiaque','miels','Miel Aphrodisiaque','Une préparation noble, héritée des traditions du désert.',ARRAY['Un assemblage précieux de miel et de plantes réputées pour la vitalité, transmis dans les cultures orientales depuis des générations.','Un produit d''exception, à offrir ou à savourer dans les moments qui comptent.']::text[],ARRAY['Soutient la vitalité et l''énergie','Tonifiant naturel','Préparation riche et concentrée','Tradition orientale']::text[],NULL,'Miel pur, Gelée Royale, Propolis, Ginseng, Ashwaganda, Moringa, Costus, Shilajit, Spiruline, Hibiscus','Préparation artisanale','1 à 2 cuillères à café par jour, le matin à jeun ou en journée. Peut être consommé seul ou dilué dans une boisson tiède.',ARRAY['Produit artisanal : la couleur, la texture et l''intensité peuvent varier selon les lots.','Ne remplace pas un traitement médical.','À conserver dans un endroit sec et à l''abri de la lumière.']::text[],'50 g, 200 g, 300 g',NULL,19.99,ARRAY['format']::text[],ARRAY['assets/produits-ia/miel-aphrodisiaque/miel-aphrodisiaque-2.webp','assets/produits-ia/miel-aphrodisiaque/miel-aphrodisiaque-1.webp']::text[],'[]'::jsonb,true,false,1) on conflict (slug) do nothing;
