insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('grn-chardon','poudres','Graine de Chardon','L''allié du foie, connu des herboristes.',ARRAY['Des graines issues du chardon-Marie, plante reconnue dans les traditions herboristes pour son action sur le foie.','À infuser dans de l''eau chaude ou à mâcher.']::text[],ARRAY['Soutient la fonction hépatique','Aide à protéger le foie','Favorise la détoxification naturelle','Riche en antioxydants']::text[],NULL,'Graines de Chardon-Marie (Silybum marianum)','Méditerranée / Europe','1 à 2 cuillères à café par jour, à infuser dans de l''eau chaude après les repas ou à mâcher. Idéal le matin ou après les repas.',ARRAY['Déconseillé aux femmes enceintes et allaitantes.','Ne remplace pas un traitement médical.','À conserver dans un endroit sec et à l''abri de la lumière.']::text[],'50 g',NULL,4.99,ARRAY[]::text[],ARRAY['assets/produits-ia/grn-chardon/grn-chardon-1.webp']::text[],'[]'::jsonb,true,false,44) on conflict (slug) do nothing;
