insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('hl-gingembre','huiles','Huile de Gingembre','La chaleur de la racine en quelques gouttes.',ARRAY['Une huile naturelle obtenue à partir du gingembre, réputée pour ses propriétés réchauffantes et tonifiantes.','100% naturelle et biologique, sans paraben ni silicone.']::text[],ARRAY['Réchauffe et tonifie','Apaise les tensions musculaires','Stimulante naturelle','100% naturelle']::text[],NULL,'Huile de Gingembre','Sélection spécialisée','Diluer dans une huile végétale et masser l''abdomen pour soulager les ballonnements, la constipation ou les nausées. Peut aussi s''utiliser en massage tonifiant ou en soin capillaire.',ARRAY['Usage externe uniquement sauf indication contraire.','Toujours diluer avant application sur la peau.','Éviter le contact avec les yeux.','Sans additifs ni conservateurs, sans paraben ni silicone.','Non testée sur les animaux.']::text[],NULL,'30 mL',9.99,ARRAY[]::text[],ARRAY['assets/produits-ia/hl-gingembre/hl-gingembre-1.webp']::text[],'[]'::jsonb,true,false,46) on conflict (slug) do nothing;
