insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('hl-citron','huiles','Huile de Citron','L''éclat vivifiant des agrumes.',ARRAY['Une huile fraîche et tonifiante issue du citron, traditionnellement appréciée pour son parfum vif et purifiant.','100% naturelle et biologique, sans paraben ni silicone.']::text[],ARRAY['Tonifiante et vivifiante','Purifiante','Parfum frais d''agrumes','100% naturelle']::text[],NULL,'Huile de Citron','Sélection spécialisée','Utiliser en soin de la peau dilué dans une huile végétale ou en massage. Quelques gouttes en diffusion permettent de purifier l''air.',ARRAY['Usage externe uniquement sauf indication contraire.','Toujours diluer avant application sur la peau.','Éviter le contact avec les yeux.','Sans additifs ni conservateurs, sans paraben ni silicone.','Non testée sur les animaux.']::text[],NULL,'30 mL',9.99,ARRAY[]::text[],ARRAY['assets/produits-ia/hl-citron/hl-citron-1.webp']::text[],'[]'::jsonb,true,false,60) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('hl-menthe-pouliot','huiles','Huile de Menthe Pouliot','La menthe sauvage aux notes puissantes.',ARRAY['Une huile à la fraîcheur prononcée issue de la menthe pouliot, traditionnellement utilisée pour son parfum intense.','100% naturelle et biologique, sans paraben ni silicone.']::text[],ARRAY['Fraîcheur intense','Parfum puissant','Tonifiante','100% naturelle']::text[],NULL,'Huile de Menthe Pouliot','Sélection spécialisée','Diluer dans une huile végétale pour massage du ventre ou du corps. Peut aussi s''utiliser en diffusion ou en usage externe dilué en évitant le contact avec les yeux.',ARRAY['Usage externe uniquement sauf indication contraire.','Toujours diluer avant application sur la peau.','Éviter le contact avec les yeux.','Sans additifs ni conservateurs, sans paraben ni silicone.','Non testée sur les animaux.']::text[],NULL,'30 mL',9.99,ARRAY[]::text[],ARRAY['assets/produits-ia/hl-menthe-pouliot/hl-menthe-pouliot-1.webp']::text[],'[]'::jsonb,true,false,61) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('br-nila','brumes','Spray Nila','La fraîcheur de la rose de Nila et du citron.',ARRAY['Une brume rafraîchissante à base d''eau de rose de Nila et de citron, pour réveiller et illuminer la peau à tout moment.','Préparation artisanale, flacon spray de 100 mL.']::text[],ARRAY['Rafraîchit instantanément','Illumine le teint','Parfum délicat','Préparation artisanale']::text[],NULL,'Eau de rose de Nila, eau de citron, sans alcool, sans colorant, sans conservateur, 100% d''ingrédients d''origine naturelle','Préparé artisanalement par Dar Nūr, inspiré des traditions naturelles et des savoirs ancestraux','Vaporiser sur le visage ou le corps à tout moment de la journée. Utiliser après le nettoyage pour tonifier la peau, avant le maquillage pour un teint frais, ou comme brume rafraîchissante.',ARRAY['Usage externe uniquement, éviter le contour des yeux.','Produit artisanal : couleur, texture et intensité peuvent varier selon les lots.','À conserver à l''abri de la chaleur et de la lumière.']::text[],NULL,'100 mL',19.99,ARRAY[]::text[],ARRAY['spray-nila-2.webp','spray-nila-1.webp']::text[],'[]'::jsonb,true,false,62) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('br-sublimante','brumes','Brume Sublimante Rose & Argan','Un soin précieux pour sublimer votre beauté.',ARRAY['Une brume naturelle précieuse à base d''eau de rose, d''huile d''argan et de rose d''Arabie, qui hydrate, illumine et adoucit la peau.','Un soin délicat pour sublimer votre beauté au quotidien. Flacon spray de 100 mL.']::text[],ARRAY['Illumine et hydrate la peau','Protège et adoucit l''épiderme','Prévient le vieillissement cutané','Délicat parfum floral']::text[],NULL,'Eau de rose, huile d''argan, rose d''Arabie','Préparé artisanalement par Dar Nūr, inspiré des traditions naturelles et des savoirs ancestraux','Vaporiser sur le visage ou le corps à environ 20 cm. Fermer les yeux lors de l''application, secouer avant emploi et ne pas rincer.',ARRAY['Usage externe uniquement, éviter le contour des yeux.','Produit artisanal : couleur, texture et intensité peuvent varier selon les lots.','À conserver à l''abri de la chaleur et de la lumière.']::text[],NULL,'100 mL',19.99,ARRAY[]::text[],ARRAY['assets/produits-ia/br-sublimante/br-sublimante-1.webp','assets/produits-ia/br-sublimante/br-sublimante-2.webp']::text[],'[]'::jsonb,true,false,63) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('br-eau-rose','brumes','Eau de Rose Pur','La fraîcheur et la pureté à l''état naturel.',ARRAY['Une brume florale 100% naturelle, obtenue par distillation délicate des pétales de rose. Elle rafraîchit, tonifie et illumine la peau.','Un soin doux et polyvalent pour le visage, le cou et tous les types de peau. Sans alcool, sans colorant, sans conservateur.']::text[],ARRAY['Rafraîchit et tonifie la peau','Apaise les irritations et rougeurs','Hydrate et équilibre le pH','Convient à tous les types de peau']::text[],NULL,'Eau de rose (distillation de pétales de rose), sans alcool, sans colorant, sans conservateur, 100% naturel','Préparé artisanalement par Dar Nūr, inspiré des traditions naturelles et des savoirs ancestraux','Vaporiser sur le visage ou le corps à tout moment de la journée. Appliquer matin et soir à l''aide d''un coton sur le visage et le cou, puis laisser pénétrer sans rincer.',ARRAY['Usage externe uniquement, éviter le contour des yeux.','Produit artisanal : couleur, texture et intensité peuvent varier selon les lots.','À conserver à l''abri de la chaleur et de la lumière.']::text[],NULL,'100 mL',5.99,ARRAY[]::text[],ARRAY['assets/produits-ia/br-eau-rose/br-eau-rose-1.webp']::text[],'[]'::jsonb,true,false,64) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('br-apaisante','brumes','Spray Apaisante aux Plantes Sacrées','Une brume raffinée pour le calme et l''harmonie.',ARRAY['Une brume aux plantes sacrées, conçue pour apaiser, rafraîchir et purifier la peau. Un soin naturel pour une sensation de calme et de bien-être.','À base de Rose d''Oliban, Gomme Arabique et Lavande. Sans alcool, sans colorant. Flacon spray de 100 mL.']::text[],ARRAY['Rafraîchit, apaise et purifie','Calme et réduit les tensions','Sublime et hydrate le teint','Délicat parfum relaxant']::text[],NULL,'Rose d''Oliban, Gomme Arabique, Lavande, eau florale, excipients naturels, sans alcool, sans colorant','Préparé artisanalement par Dar Nūr, inspiré des traditions naturelles et des savoirs ancestraux','Vaporiser sur le visage ou le corps à tout moment de la journée, à environ 20 cm de la peau. Fermer les yeux lors de l''application et secouer avant emploi.',ARRAY['Usage externe uniquement, éviter le contour des yeux.','Produit artisanal : couleur, texture et intensité peuvent varier selon les lots.','À conserver à l''abri de la chaleur et de la lumière.']::text[],NULL,'100 mL',19.99,ARRAY[]::text[],ARRAY['assets/produits-ia/br-apaisante/br-apaisante-2.webp','spray-aromatherapy.webp']::text[],'[]'::jsonb,true,false,65) on conflict (slug) do nothing;
