insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-musc-tahara-0','tahara','Musc Tahara Lavande 6ml',NULL,ARRAY['Le musc Tahara, également appelé musc blanc ou musc intime, est un parfum traditionnel originaire du Moyen-Orient. Il est utilisé principalement pour l''hygiène intime féminine et symbolise la pureté, comme son nom l''indique en arabe. Ce produit, souvent sans alcool, se présente sous une texture épaisse et blanche. Il est apprécié pour ses propriétés purifiantes, apaisantes et odorantes, offrant un parfum subtil rappelant le propre. Traditionnellement, il est employé après les ablutions ou les menstruations pour parfumer et purifier le corps']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,8.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-musc-tahara-0/dn-musc-tahara-0.webp']::text[],'[]'::jsonb,true,false,102) on conflict (slug) do nothing;
