insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-parfum-200-0','parfums','Ameer el oud Original 100 ML',NULL,ARRAY['Ameer Al Oud Original est un parfum caractérisé par des notes boisées d''oud, de vanille et de sucre. Conçu pour les occasions spéciales, ce parfum offre une fragrance intense et sophistiquée, idéal pour l''automne et l''hiver. Sa composition complexe combine des notes de bois d''agar, de vanille et de bois de santal, créant un sillage chaleureux et mémorable']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,29.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-parfum-200-0/dn-parfum-200-0.webp']::text[],'[]'::jsonb,true,false,105) on conflict (slug) do nothing;
