insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-parfum-200-2','parfums','L''ambre Brut',NULL,ARRAY['L''ambré brut est un parfum oriental boisé lancé en. Il offre un voyage olfactif captivant avec des notes de bergamote de Sicile, poivre rose et davana en tête, ambre blanche et oud au cœur, et une base de cuir, musc et vétiver d''Haïti. Cette fragrance sophistiquée évoque des paysages contrastés, mêlant fraîcheur et chaleur, pour un sillage élégant et séduisant.']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,49.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-parfum-200-2/dn-parfum-200-2.webp']::text[],'[]'::jsonb,true,false,107) on conflict (slug) do nothing;
