insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-bakhour-0','bakhour','Bakhur Mukhalat',NULL,ARRAY['Le Bakhur Mukhalat est un encens traditionnel arabe, composé de bois précieux, de résines et d''essences parfumées. Sa fragrance complexe mêle des notes de bois d''oud, de rose et de musc, créant une atmosphère riche et enveloppante. Utilisé pour parfumer les intérieurs et lors de cérémonies, il symbolise l''hospitalité et la spiritualité du monde arabe, se consumant sur des charbons ardents pour libérer son parfum subtil et profond.']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,24.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-bakhour-0/dn-bakhour-0.webp']::text[],'[]'::jsonb,true,false,111) on conflict (slug) do nothing;
