insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-rose-imperial-valley','parfums','Rosé de l''impérial valley','Parfum impérial valley 200ML',ARRAY['Parfum impérial valley 200ML. L''ambré brut est un parfum oriental boisé lancé en. Il offre un voyage olfactif captivant avec des notes de bergamote de Sicile, poivre rose et davana en tête, ambre blanche et oud au cœur, et une base de cuir, musc et vétiver d''Haïti. Cette fragrance sophistiquée évoque des paysages contrastés, mêlant fraîcheur et chaleur, pour un sillage élégant et séduisant.']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,49.9,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-rose-imperial-valley/dn-rose-imperial-valley.webp']::text[],'[]'::jsonb,true,false,187) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-ismid-medine','poudres','Ismid de Médine',NULL,ARRAY['L''ismid (ou ithmid) est un khôl traditionnel souvent utilisé en médecine prophétique et en cosmétique, principalement dans les pays arabes et asiatiques. Il est généralement composé de sulfure d''antimoine et parfois d''autres minéraux. Voici quelques-uns de ses bienfaits supposés : 1. Amélioration de la vision : selon certaines traditions, l''application régulière d''ismid sur les paupières renforcerait la vue et protégerait les yeux contre les infections. 2. Traitement des maladies oculaires : il est réputé pour aider contre les irritations, les rougeurs et certains problèmes comme la conjonctivite. 3. Renforcement et croissance des cils : il favoriserait la pousse des cils et les rendrait plus épais. 4. Propriétés antibactériennes : il aide à protéger les yeux contre certaines bactéries et infections. 5. Utilisation cosmétique : il donne un regard intense et était utilisé comme maquillage naturel depuis l''Antiquité. 6. Propriétés anti-inflammatoires : certains affirment qu''il peut réduire les inflammations des yeux. Précautions d''utilisation : il est important d''utiliser un ismid pur et naturel, car certains produits contrefaits peuvent contenir des métaux lourds dangereux. Son utilisation est déconseillée aux personnes allergiques aux minéraux ou souffrant de problèmes oculaires graves sans avis médical.']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY['Déconseillé aux femmes enceintes et allaitantes.','Ne remplace pas un traitement médical.','À conserver dans un endroit sec et à l''abri de la lumière.']::text[],'50 g',NULL,6.9,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-ismid-medine/dn-ismid-medine.webp']::text[],'[]'::jsonb,true,false,189) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-musc-tahara-grenade','tahara','Musc Tahara Grenade 6ml',NULL,ARRAY['Le musc Tahara, également appelé musc blanc ou musc intime, est un parfum traditionnel originaire du Moyen-Orient. Il est utilisé principalement pour l''hygiène intime féminine et symbolise la pureté, comme son nom l''indique en arabe. Ce produit, souvent sans alcool, se présente sous une texture épaisse et blanche. Il est apprécié pour ses propriétés purifiantes, apaisantes et odorantes, offrant un parfum subtil rappelant le propre. Traditionnellement, il est employé après les ablutions ou les menstruations pour parfumer et purifier le corps']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY[]::text[],NULL,NULL,8.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-musc-tahara-grenade/dn-musc-tahara-grenade.webp']::text[],'[]'::jsonb,true,false,190) on conflict (slug) do nothing;
insert into public.products (slug,category_id,name,tagline,description,benefits,benefits_label,composition,provenance,usage_advice,precautions,weight,volume,price_value,variant_axes,images,accordions,active,featured,sort_order) values ('dn-poudre-de-sidr-50g','poudres','Poudre De Sidr 50g',NULL,ARRAY['La poudre de sidr, issue des feuilles du jujubier (mentionné dans le Coran), est un ingrédient naturel aux multiples bienfaits. En Islam, elle est utilisée dans des pratiques spirituelles comme la roqya ou la toilette mortuaire. Riche en saponines, elle nettoie en douceur, apaise le cuir chevelu, lutte contre les pellicules et fixe les colorations végétales. Idéale pour tous les types de cheveux, elle apporte force, brillance et volume tout en respectant les traditions religieuses et naturelles.']::text[],ARRAY[]::text[],NULL,NULL,'Dar Nūr — Made in Medina & Cairo',NULL,ARRAY['Déconseillé aux femmes enceintes et allaitantes.','Ne remplace pas un traitement médical.','À conserver dans un endroit sec et à l''abri de la lumière.']::text[],'50 g',NULL,5.99,ARRAY[]::text[],ARRAY['assets/produits-fournisseur/dn-poudre-de-sidr-50g/dn-poudre-de-sidr-50g.webp']::text[],'[]'::jsonb,true,false,191) on conflict (slug) do nothing;
